const body = $input.first().json.body;

// Filtra apenas mensagens reais de texto (ignora e2e_notification, status, etc)
const isRealMessage = (
  body.event === 'message' &&
  !body.payload.fromMe &&
  body.payload.body &&
  body.payload.body.trim() !== '' &&
  body.payload._data?.type !== 'e2e_notification'
);

if (isRealMessage) {
  return $input.all();
}
return [];

